{"meta": null, "content": [{"type": "text", "text": "{"content":"14000:    p -- print raw symbol name.\n14001:    X -- don't print any sort of PIC '@' suffix for a symbol.\n14002:    \u0026 -- print some in-use local-dynamic symbol name.\n14003:    H -- print a memory address offset by 8; used for sse high-parts\n14004:    Y -- print condition for XOP pcom* instruction.\n14005:    V -- print naked full integer register name without %.\n14006:    v -- print segment override prefix\n14007:    + -- print a branch hint as 'cs' or 'ds' prefix\n14008:    ; -- print a semicolon (after prefixes due to bug in older gas).\n14009:    ~ -- print \"i\" if TARGET_AVX2, \"f\" otherwise.\n14010:    ^ -- print addr32 prefix if Pmode != word_mode\n14011:    M -- print addr32 prefix for TARGET_X32 with VSIB address.\n14012:    ! -- print NOTRACK prefix for jxx/call/ret instructions if required.\n14013:    N -- print maskz if it's constant 0 operand.\n14014:    G -- print embedded flag for ccmp/ctest.\n14015:  */\n14016: \n14017: void\n14018: ix86_print_operand (FILE *file, rtx x, int code)\n14019: {\n14020:   if (code)\n14021:     {\n14022:       switch (code)\n14023: \t{\n14024: \tcase 'A':\n14025: \t  switch (ASSEMBLER_DIALECT)\n14026: \t    {\n14027: \t    case ASM_ATT:\n14028: \t      putc ('*', file);\n14029: \t      break;\n14030: \n14031: \t    case ASM_INTEL:\n14032: \t      /* Intel syntax. For absolute addresses, registers should not\n14033: \t\t be surrounded by braces.  */\n14034: \t      if (!REG_P (x))\n14035: \t\t{\n14036: \t\t  putc ('[', file);\n14037: \t\t  ix86_print_operand (file, x, 0);\n14038: \t\t  putc (']', file);\n14039: \t\t  return;\n14040: \t\t}\n14041: \t      break;\n14042: \n14043: \t    default:\n14044: \t      gcc_unreachable ();\n14045: \t    }\n14046: \n14047: \t  ix86_print_operand (file, x, 0);\n14048: \t  return;\n14049: \n14050: \tcase 'E':\n14051: \t  /* Wrap address in an UNSPEC to declare special handling.  */\n14052: \t  if (TARGET_64BIT)\n14053: \t    x = gen_rtx_UNSPEC (DImode, gen_rtvec (1, x), UNSPEC_LEA_ADDR);\n14054: \n14055: \t  output_address (VOIDmode, x);\n14056: \t  return;\n14057: \n14058: \tcase 'L':\n14059: \t  if (ASSEMBLER_DIALECT == ASM_ATT)\n14060: \t    putc ('l', file);\n14061: \t  return;\n14062: \n14063: \tcase 'W':\n14064: \t  if (ASSEMBLER_DIALECT == ASM_ATT)\n14065: \t    putc ('w', file);\n14066: \t  return;\n14067: \n14068: \tcase 'B':\n14069: \t  if (ASSEMBLER_DIALECT == ASM_ATT)\n14070: \t    putc ('b', file);\n14071: \t  return;\n14072: \n14073: \tcase 'Q':\n14074: \t  if (ASSEMBLER_DIALECT == ASM_ATT)\n14075: \t    putc ('l', file);\n14076: \t  return;\n14077: \n14078: \tcase 'S':\n14079: \t  if (ASSEMBLER_DIALECT == ASM_ATT)\n14080: \t    putc ('s', file);\n14081: \t  return;\n14082: \n14083: \tcase 'T':\n14084: \t  if (ASSEMBLER_DIALECT == ASM_ATT)\n14085: \t    putc ('t', file);\n14086: \t  return;\n14087: \n14088: \tcase 'O':\n14089: #ifdef HAVE_AS_IX86_CMOV_SUN_SYNTAX\n14090: \t  if (ASSEMBLER_DIALECT != ASM_ATT)\n14091: \t    return;\n14092: \n14093: \t  switch (GET_MODE_SIZE (GET_MODE (x)))\n14094: \t    {\n14095: \t    case 2:\n14096: \t      putc ('w', file);\n14097: \t      break;\n14098: \n14099: \t    case 4:\n14100: \t      putc ('l', file);\n14101: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/gcc--96dfb333@baaf9b33ef307e3d2752a94e62274c374e6a5e20/-/blob/gcc/config/i386/i386.cc%3FL14000-14100"}", "annotations": null, "meta": null}], "structuredContent": {"content": "14000:    p -- print raw symbol name.
