18022: int
18023: ix86_attr_length_vex_default (rtx_insn *insn, bool has_0f_opcode,
18024: 			      bool has_vex_w)
18025: {
18026:   int i, reg_only = 2 + 1;
18027:   bool has_mem = false;
18028: 
18029:   /* Only 0f opcode can use 2 byte VEX prefix and  VEX W bit uses 3
18030:      byte VEX prefix.  */
18031:   if (!has_0f_opcode || has_vex_w)
18032:     return 3 + 1;
18033: 
18034:  /* We can always use 2 byte VEX prefix in 32bit.  */
18035:   if (!TARGET_64BIT)
18036:     return 2 + 1;
18037: 
18038:   extract_insn_cached (insn);
18039: 
18040:   for (i = recog_data.n_operands - 1; i >= 0; --i)
18041:     if (REG_P (recog_data.operand[i]))
18042:       {
18043: 	/* REX.W bit uses 3 byte VEX prefix.
18044: 	   REX2 with vex use extended EVEX prefix length is 4-byte.  */
18045: 	if (GET_MODE (recog_data.operand[i]) == DImode
18046: 	    && GENERAL_REG_P (recog_data.operand[i]))
