18050: 	   operand will be encoded using VEX.B, so be conservative.
18051: 	   REX2 with vex use extended EVEX prefix length is 4-byte.  */
18052: 	if (REX_INT_REGNO_P (recog_data.operand[i])
18053: 	    || REX2_INT_REGNO_P (recog_data.operand[i])
18054: 	    || REX_SSE_REGNO_P (recog_data.operand[i]))
18055: 	  reg_only = 3 + 1;
18056:       }
18057:     else if (MEM_P (recog_data.operand[i]))
18058:       {
18059: 	/* REX2.X or REX2.B bits use 3 byte VEX prefix.  */
18060: 	if (x86_extended_rex2reg_mentioned_p (recog_data.operand[i]))
18061: 	  return 4;
18062: 
18063: 	/* REX.X or REX.B bits use 3 byte VEX prefix.  */
18064: 	if (x86_extended_reg_mentioned_p (recog_data.operand[i]))
18065: 	  return 3 + 1;
18066: 
